text:
&-horizontal {
  flex-direction: row;
  > .@{class-prefix-space}-item {
    margin-right: var(--gap-horizontal);
    &:last-child {
      margin-right: 0;
    }
  }
  &.@{class-prefix-space}-wrap {
    flex-wrap: wrap;
    margin-bottom: calc(var(--gap-vertical) * -1);
    > .@{class-prefix-space}-item {
      padding-bottom: var(--gap-vertical);
    }
  }
}

& when not (@variationTransitionColors = false) {
    each(@variationTransitionColors, {
        @color: @value;
        @c: @colors[@@color][color];
        @l: @colors[@@color][light];

        .@{color}.pulsating.transition {
            box-shadow: 0 0 0 0 fade(@c, @pulsatingOpacity);
        }
        & when (@variationTransitionInverted) {
            .@{color}.inverted.pulsating.transition {
                box-shadow: 0 0 0 0 fade(@l, @pulsatingInvertedOpacity);
            }
        }
    });
}

span.ui-icon.icon-ripple, div.ui-icon.icon-ripple {
    opacity: .9!important;

    &:before {
        border-radius: 50%;
        background-color: rgba(0,0,0,.12);
        background-size: 24px 24px;
        padding: 4px!important;
        height: 24px;
        width: 24px;
    }

    &.ui-icon-plusthick:before {
        padding-left: 5px!important;
    }
}

span.ui-icon-carat-1-e {
    background-image: none;
    display: inline;

    &:before {
        font-family: 'Glyphicons Halflings';
        color: #444444;
        position: relative;
        font-size: 10px;
        font-weight: bold;
        padding: 0 4px;
        top: 2px;
        overflow: hidden;
        content: "\e258" !important;
    }
}

&-buttons {
  position: relative;
  display: flex;
  font-size: @font-size-title;
  font-size: var(--am-modal-footer-fontSize, @font-size-title);
  color: @color-text-primary;
  color: var(--am-color-text-primary, @color-text-primary);
  text-align: center;
  .hairline('top', @modal-footer-border-color);
  &--vertical {
    flex-direction: column;
  }
  &--horizontal {
    flex-direction: row;
  }
}

&-input {
  box-sizing: content-box;
  padding-bottom: @v-spacing-standard;
  padding-bottom: var(--am-amount-input-padding-bottom, @v-spacing-standard);
  display: flex;
  align-items: baseline;
  width: 100%;
  height: 100rpx;
  overflow: hidden;
  position: relative;
  font-size: @font-size-amount-core;
  line-height: @line-height-base;
  line-height: var(--am-amount-input-line-height, @line-height-paragraph);
  .hairline("bottom");
}

& when not (@navigation__media-wrap = false) {
    @media @navigation__media-wrap {
        .header.content {
            flex-wrap: wrap;
            > .navigation-wrapper {
                order: 9999;
                width: 100%;
                margin-bottom: -@2;

                .navigation > ul {
                    .margin-left(-@2);
                }
            }
        }
    }
}

@media only screen and (max-width: @largestMobileScreen) {
    .ui.stackable.buttons {
        flex-direction: column;
        & .button:first-child {
            border-bottom-left-radius: 0;
            border-top-right-radius: @borderRadius;
        }
        & .button:last-child {
            border-bottom-left-radius: @borderRadius;
            border-top-right-radius: 0;
        }
        & .button:only-child {
            border-radius: @borderRadius;
        }
    }
}

&-title {
    display: inline-block;
    margin: 0;
    padding: 0 4px;
    border-radius: @btn-border-radius-small;
    cursor: pointer;
    vertical-align: top;
    color: @text-color;
    transition: all @transition-time @ease-in-out;
    &:hover {
        background-color: tint(@primary-color, 90%);
    }
    &-selected, &-selected:hover{
        background-color: tint(@primary-color, 80%);
    }
}

&-bar-con {
    position: absolute;
    overflow: hidden;
    &.vertical {
        left: @trigger-bar-offset;
        top: 50%;
        height: @trigger-bar-con-height;
        transform: translate(0, -50%);
    }
    &.horizontal {
        left: 50%;
        top: @trigger-bar-offset;
        width: @trigger-bar-con-height;
        transform: translate(-50%, 0);
    }
}

&:active,
  &.active,
  .open > .dropdown-toggle& {
    color: @color;
    background-color: darken(@background, 10%);
    background-image: none;
    border-color: darken(@border, 12%);

    &:hover,
    &:focus,
    &.focus {
      color: @color;
      background-color: darken(@background, 17%);
      border-color: darken(@border, 25%);
    }
  }

&-body {
  display: flex;
  align-items: center;
  width: 100%;
  padding: 19px @h-spacing-large;
  padding: 19px var(--am-card-padding, @h-spacing-large);
  border-radius: @corner-radius-lg;
  border-radius: var(--am-card-border-radius, @corner-radius-lg);
  min-height: 85px;
  box-sizing: border-box;
  background-color: #929292;
  background-repeat: no-repeat;
  z-index: 2;
  position: relative;
  background-size: 100%;
}

i.icon {
    display: inline-block;
    opacity: @opacity;
    margin: 0 @distanceFromText 0 0;
    width: @width;
    height: @height;
    font-family: @fontName;
    font-style: normal;
    font-weight: @normal;
    text-decoration: inherit;
    text-align: center;
    speak: none;
    -moz-osx-font-smoothing: grayscale;
    -webkit-font-smoothing: antialiased;
    backface-visibility: hidden;
}

&:before{
    content: '';
    display: none;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background-color: transparent;
    position: absolute;
    left: 3px;
    top: 3px;
    z-index: 1;
    border: 1px solid @primary-color;
    border-color: transparent transparent transparent @primary-color;
    animation: switch-loading 1s linear;
    animation-iteration-count: infinite;
}

&-disabled {
    border-color: @border-color-base;
    background-color: @background-color-base;
    cursor: @cursor-disabled;
    color: #ccc;

    &:first-child,
    &:hover {
        border-color: @border-color-base;
        background-color: @background-color-base;
        color: #ccc;
    }
    &:first-child {
        border-left-color: @border-color-base;
    }
}

@media @media-hover-none {
    & when (@listing-grid-item-actions-secondary__position = absolute) {
        .product-item-inner,
        .actions-secondary {
            opacity: 1;
            pointer-events: all;
        }
    }
    & when not (@_hover-none-visible-height = false) {
        .actions-primary {
            opacity: 0;
            pointer-events: none;
        }
        .listing-reveal-on-hover-visible-height(@_aspect-ratio, @_hover-none-visible-height);
    }
}

tbody tr { // tbody is created per product
            &:not(:last-child) {
                border-bottom: 0;
            }
            + tr { // bundle items
                td:first-child {
                    .padding-left(@4);
                }
                &:not(:last-child) {
                    td {
                        padding-top: @1;
                        padding-bottom: @1;
                    }
                }
            }
        }

& when not (@variationButtonColors = false) {
    each(@variationButtonColors, {
        @color: @value;
        @h: @colors[@@color][hover];
        @lh: @colors[@@color][lightHover];

        input[type="file"].ui.file.input:focus + label.ui.@{color}.button@{notBasic}@{notTertiary},
        .ui.file.input input[type="file"]:focus + label.ui.@{color}.button@{notBasic}@{notTertiary} {
            background-color: @h;
            color: @white;
            &.inverted when (@variationButtonInverted) {
                background-color: @lh;
            }
        }
    });
}

@media only screen and (min-width: 992px) and (max-width: 1199.98px) {
  .ui.ui.ui.container:not(.fluid) {
    width: 933px;
    margin-left: auto;
    margin-right: auto;
  }
  .ui.ui.ui.grid.container {
    width: calc(933px + 2rem);
  }
  .ui.ui.ui.relaxed.grid.container {
    width: calc(933px + 3rem);
  }
  .ui.ui.ui.very.relaxed.grid.container {
    width: calc(933px + 5rem);
  }
}

@media only screen and (min-width: 768px) and (max-width: 991.98px) {
  .ui.ui.ui.container:not(.fluid) {
    width: 723px;
    margin-left: auto;
    margin-right: auto;
  }
  .ui.ui.ui.grid.container {
    width: calc(723px + 2rem);
  }
  .ui.ui.ui.relaxed.grid.container {
    width: calc(723px + 3rem);
  }
  .ui.ui.ui.very.relaxed.grid.container {
    width: calc(723px + 5rem);
  }
}

&:hover,
  &:focus {
    & when (@theme = dark) {
      .button-color(
        colorPalette('@{error-color}', 7); @btn-default-bg; colorPalette('@{error-color}', 7)
      );
    }
    & when (not (@theme = dark) and not (@theme = variable)) {
      .button-color(
        colorPalette('@{error-color}', 5); @btn-default-bg; colorPalette('@{error-color}', 5)
      );
    }
    & when (@theme = variable) {
      .button-color(@error-color-hover, @btn-default-bg, @error-color-hover);
    }
  }

&-slide-up-leave&-slide-up-leave-active&-placement-bottomLeft,
    &-slide-up-leave&-slide-up-leave-active&-placement-bottomRight {
      animation-name: rcDropdownSlideUpOut;
      animation-play-state: running;
    }

    &-slide-up-leave&-slide-up-leave-active&-placement-topLeft,
    &-slide-up-leave&-slide-up-leave-active&-placement-topRight {
      animation-name: rcDropdownSlideDownOut;
      animation-play-state: running;
    }

&-container {
  position: relative;
  background-color: @modal-container-bg;
  border: 1px solid @modal-container-fallback-border-color; //old browsers fallback (ie8 etc)
  border: 1px solid @modal-container-border-color;
  border-radius: @border-radius-large;
  box-shadow: 0 3px 9px rgba(0, 0, 0, .5);
  background-clip: padding-box;
  // Remove focus outline from opened rc-dialog
  outline: 0;
}

> tbody:last-child,
    > tfoot:last-child {
      > tr:last-child {
        border-bottom-left-radius: (@panel-border-radius - 1);
        border-bottom-right-radius: (@panel-border-radius - 1);

        td:first-child,
        th:first-child {
          border-bottom-left-radius: (@panel-border-radius - 1);
        }
        td:last-child,
        th:last-child {
          border-bottom-right-radius: (@panel-border-radius - 1);
        }
      }
    }

> thead:first-child,
    > tbody:first-child {
      > tr:first-child {
        border-top-left-radius: (@panel-border-radius - 1);
        border-top-right-radius: (@panel-border-radius - 1);

        td:first-child,
        th:first-child {
          border-top-left-radius: (@panel-border-radius - 1);
        }
        td:last-child,
        th:last-child {
          border-top-right-radius: (@panel-border-radius - 1);
        }
      }
    }

&.bottom > .arrow {
  left: 50%;
  margin-left: -@popover-arrow-outer-width;
  border-top-width: 0;
  border-bottom-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-bottom-color: @popover-arrow-outer-color;
  top: -@popover-arrow-outer-width;
  &:after {
    content: " ";
    top: 1px;
    margin-left: -@popover-arrow-width;
    border-top-width: 0;
    border-bottom-color: @popover-arrow-color;
  }
}

&.top > .arrow {
  left: 50%;
  margin-left: -@popover-arrow-outer-width;
  border-bottom-width: 0;
  border-top-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-top-color: @popover-arrow-outer-color;
  bottom: -@popover-arrow-outer-width;
  &:after {
    content: " ";
    bottom: 1px;
    margin-left: -@popover-arrow-width;
    border-bottom-width: 0;
    border-top-color: @popover-arrow-color;
  }
}

&.left > .arrow {
  top: 50%;
  right: -@popover-arrow-outer-width;
  margin-top: -@popover-arrow-outer-width;
  border-right-width: 0;
  border-left-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-left-color: @popover-arrow-outer-color;
  &:after {
    content: " ";
    right: 1px;
    border-right-width: 0;
    border-left-color: @popover-arrow-color;
    bottom: -@popover-arrow-width;
  }
}

&.right > .arrow {
  top: 50%;
  left: -@popover-arrow-outer-width;
  margin-top: -@popover-arrow-outer-width;
  border-left-width: 0;
  border-right-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-right-color: @popover-arrow-outer-color;
  &:after {
    content: " ";
    left: 1px;
    bottom: -@popover-arrow-width;
    border-left-width: 0;
    border-right-color: @popover-arrow-color;
  }
}

&.bottom .arrow {
  left: 50%;
  margin-left: -@popover-arrow-outer-width;
  border-top-width: 0;
  border-bottom-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-bottom-color: @popover-arrow-outer-color;
  top: -@popover-arrow-outer-width;
  &:after {
    content: " ";
    top: 1px;
    margin-left: -@popover-arrow-width;
    border-top-width: 0;
    border-bottom-color: @popover-arrow-color;
  }
}
